o.merchant_id = 1
AND o.is_deleted = 0

    AND o.order_no = #{q.orderNo}


    AND o.order_status = #{q.orderStatus}


    AND (o.customer_name LIKE CONCAT('%', #{q.customerKeyword}, '%')
    OR o.customer_mobile LIKE CONCAT('%', #{q.customerKeyword}, '%'))


    AND o.created_at >= #{q.startTime}


    AND o.created_at <= #{q.endTime}
